mapper.select:
SELECT sp.id, sp.point_code AS pointCode, sp.point_name AS pointName, sp.project_id AS projectId, sp.section_id AS sectionId, sp.outfall_type AS outfallType, sp.longitude, sp.latitude, sp.region, sp.assignee_id AS assigneeId, sp.collector_id AS collectorId, sp.status, sp.abnormal_tag AS abnormalTag, sp.create_time AS createTime, sp.update_time AS updateTime, p.project_name AS projectName, p.project_code AS projectCode, ps.section_name AS sectionName, u1.username AS collectorName, u2.username AS assigneeName FROM survey_point sp LEFT JOIN project p ON sp.project_id = p.id LEFT JOIN project_section ps ON sp.section_id = ps.id LEFT JOIN sys_user u1 ON sp.collector_id = u1.id LEFT JOIN sys_user u2 ON sp.assignee_id = u2.id WHERE sp.is_deleted = 0
AND sp.project_id = #{projectId}
AND sp.section_id = #{sectionId}
AND (sp.point_name LIKE CONCAT('%', #{keyword}, '%') OR sp.point_code LIKE CONCAT('%', #{keyword}, '%'))
AND sp.status = #{status}
ORDER BY sp.create_time DESC
